import{_ as t,H as e,f as i,i as l}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"Git 系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"../gitLearning/00-写作计划.md","filePath":"../gitLearning/00-写作计划.md","lastUpdated":1778496697000}'),n={name:"../gitLearning/00-写作计划.md"};function s(o,a,r,d,h,c){return e(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="git-系列写作计划" tabindex="-1">Git 系列写作计划 <a class="header-anchor" href="#git-系列写作计划" aria-label="Permalink to &quot;Git 系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 没明写,但写到第六个系列时自然出现的&quot;基础设施&quot;——所有其他系列都默认你会 git,但<strong>真正把 git 用熟的人不到 20%</strong>。 这个系列不是&quot;git 命令大全&quot;,是<strong>用工程师视角讲清楚 git 的心智模型</strong>——为什么是 DAG、为什么有 staging、为什么 rebase 会改历史、为什么 reflog 能救命。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>四层结构,跟其他系列一样从底往上:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智 + 基础(三层模型 / 提交 / 历史)</span></span>
<span class="line"><span>   → 协作(分支 / 合并 / 远程)</span></span>
<span class="line"><span>   → 应急 + 整理(stash / cherry-pick / 撤销 / reflog)</span></span>
<span class="line"><span>   → 工程化(工作流 / hooks / 大仓库 / 安全 / 高级技巧)</span></span></code></pre></div><p>不重复 GitHub 教程已经讲烂的&quot;clone 一个仓库&quot;,而是聚焦<strong>真实工程场景下会让你卡 30 分钟的那些细节</strong>:rebase 把别人的提交搞丢、submodule 拉不下来、reflog 救回 deleted branch、bisect 找 regression、worktree 同时开两个分支……</p><hr><h2 id="篇目-22-篇" tabindex="-1">篇目(22 篇) <a class="header-anchor" href="#篇目-22-篇" aria-label="Permalink to &quot;篇目(22 篇)&quot;">​</a></h2><h3 id="第一层-心智与基础-01-05" tabindex="-1">第一层:心智与基础(01-05) <a class="header-anchor" href="#第一层-心智与基础-01-05" aria-label="Permalink to &quot;第一层:心智与基础(01-05)&quot;">​</a></h3><ul><li>[x] 01 Git 总览与心智(为什么是 DAG)</li><li>[x] 02 安装配置与三层 config</li><li>[x] 03 三层工作区模型(working / staging / repo)</li><li>[x] 04 add 与 commit 基础</li><li>[x] 05 log 与历史查看(diff / blame / show)</li></ul><h3 id="第二层-分支与协作-06-10" tabindex="-1">第二层:分支与协作(06-10) <a class="header-anchor" href="#第二层-分支与协作-06-10" aria-label="Permalink to &quot;第二层:分支与协作(06-10)&quot;">​</a></h3><ul><li>[x] 06 分支与切换</li><li>[x] 07 merge 合并与冲突</li><li>[x] 08 rebase 深入</li><li>[x] 09 远程仓库与 push / pull / fetch</li><li>[x] 10 tag 与版本发布</li></ul><h3 id="第三层-应急与整理-11-15" tabindex="-1">第三层:应急与整理(11-15) <a class="header-anchor" href="#第三层-应急与整理-11-15" aria-label="Permalink to &quot;第三层:应急与整理(11-15)&quot;">​</a></h3><ul><li>[x] 11 stash 暂存</li><li>[x] 12 cherry-pick 选择性合并</li><li>[x] 13 撤销三剑客(reset / revert / checkout)</li><li>[x] 14 reflog 找回丢失提交</li><li>[x] 15 .gitignore 详解</li></ul><h3 id="第四层-工程化与进阶-16-22" tabindex="-1">第四层:工程化与进阶(16-22) <a class="header-anchor" href="#第四层-工程化与进阶-16-22" aria-label="Permalink to &quot;第四层:工程化与进阶(16-22)&quot;">​</a></h3><ul><li>[x] 16 submodule 与 subtree</li><li>[x] 17 Git Hooks</li><li>[x] 18 Worktree 与 bisect</li><li>[x] 19 工作流模型(GitFlow / Trunk-Based / GitHub Flow)</li><li>[x] 20 Commit Message 与 PR 规范</li><li>[x] 21 大仓库性能与 LFS</li><li>[x] 22 签名提交、安全与高级技巧</li></ul><hr><h2 id="完结-2026-05-08" tabindex="-1">完结(2026/05/08) <a class="header-anchor" href="#完结-2026-05-08" aria-label="Permalink to &quot;完结(2026/05/08)&quot;">​</a></h2><p>22 篇全部完成。一气呵成,跟原计划完全一致。下一步:</p><ul><li>把里面的工作流套到真实项目(选一个工作流、配 branch protection、配 hook)</li><li>不熟的命令回来翻对应那篇</li><li>出事故时第一反应是 <code>git reflog</code>,不是删仓库重 clone</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>CI / CD 流水线</td><td>backendLearning/40 ✅</td><td>不重复,只讲 git 这一侧的 hook / branch protection</td></tr><tr><td>GitOps</td><td>backendLearning/40 ✅</td><td>不展开 ArgoCD,只讲 git 在其中的角色</td></tr><tr><td>GitHub Actions</td><td>webLearning/38 ✅</td><td>不重复,只讲 git 触发</td></tr><tr><td>Code Review 工具流</td><td>claudeLearning/30 ✅</td><td>不重复 AI 部分,讲传统 review 流程</td></tr></tbody></table><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-05 是&quot;会用 git&quot;的全部内容,优先级最高,看完能做日常工作</span></span>
<span class="line"><span>06-10 是&quot;和团队协作&quot;的核心,做开源 / 写多人项目必看</span></span>
<span class="line"><span>11-15 是&quot;出事了怎么办&quot;,每条都对应一个真实事故场景</span></span>
<span class="line"><span>16-22 是&quot;团队 / 大仓库&quot;层面,不是个人开发者的必修</span></span></code></pre></div><p><strong>一个硬指标</strong>:看完 14 篇,你应该能在不查文档的情况下,从一个误删的分支里把代码救回来。能做到的话这个系列就值了。</p>`,28)])])}const g=t(n,[["render",s]]);export{u as __pageData,g as default};
